public class Solution {
    public int maxScore(int[] nums, int k) {
        int n = nums.length;
        int[] dp = new int[n];
        int[] gcd = new int[n];
        gcd[0] = nums[0];
        for (int i = 1; i < n; i++) {
            gcd[i] = gcd(gcd[i - 1], nums[i]);
        }
        int maxScore = 0;
        for (int i = 0; i < n; i++) {
            int score = 0;
            for (int j = i; j < n; j++) {
                score = gcd(gcd[j], score);
                dp[j] = Math.max(dp[j], score * (j - i + 1));
            }
            for (int j = i; j < n; j++) {
                if (j - i <= k) {
                    dp[j] = Math.max(dp[j], dp[j - 1] + (j - i + 1) * gcd(gcd[j], gcd[j - 1]));
                }
            }
            maxScore = Math.max(maxScore, dp[n - 1]);
        }
        return maxScore;
    }

    public int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
```

